def predict_next_frame(frame, action, xy=None):
    """
    Predict the next frame for the 64x64 grid game.

    The game contains a 3×3 block of cells with value 14 that can be
    moved around the board.  The block is surrounded by cells with
    value 1 (the background).  When the block moves, the cells that
    it leaves become 1, the cells that it enters become 14, and the
    cells that were 1 or 4 and are adjacent (including diagonally)
    to the new block become 14.  Cells that were 4 and were part of
    the old block become 4 again.  All other cells remain unchanged.
    ACTION6 clears a single cell to 0.
    """
    # Deep copy the frame
    new_frame = [row[:] for row in frame]

    # Helper to set a cell
    def set_cell(r, c, val):
        if 0 <= r < 64 and 0 <= c < 64:
            new_frame[r][c] = val

    # ACTION6: clear a single cell
    if action == "ACTION6" and xy is not None:
        x, y = xy
        set_cell(y, x, 0)
        return new_frame

    # Find the 3×3 block of 14s
    block = None
    for r in range(62):
        for c in range(62):
            if all(frame[r+dr][c+dc] == 14 for dr in range(3) for dc in range(3)):
                block = (r, c)
                break
        if block:
            break

    if not block:
        return new_frame  # nothing to move

    r, c = block

    # Direction mapping
    dir_map = {
        "ACTION1": (-1, 0),   # up
        "ACTION2": (1, 0),    # down
        "ACTION3": (0, -1),  # left
        "ACTION4": (0, 1),    # right
        "ACTION5": (-1, -1),  # up-left
        "ACTION7": (1, -1),   # down-left
    }
    dr, dc = dir_map.get(action, (0, 0))

    # New top-left position
    nr, nc = r + dr, c + dc

    # Check bounds
    if not (0 <= nr < 62 and 0 <= nc < 62):
        return new_frame

    # Helper to test adjacency (including diagonals)
    def adjacent_to_new_block(rr, cc):
        return any(abs(rr - (nr + dr0)) <= 1 and abs(cc - (nc + dc0)) <= 1
                   for dr0 in range(3) for dc0 in range(3))

    # Process old block cells
    for dr0 in range(3):
        for dc0 in range(3):
            rr, cc = r + dr0, c + dc0
            old_val = frame[rr][cc]
            if old_val == 14:
                set_cell(rr, cc, 1)          # block leaves -> 1
            elif old_val == 4:
                set_cell(rr, cc, 4)          # border 4 that was part of block stays 4

    # Process new block cells
    for dr0 in range(3):
        for dc0 in range(3):
            rr, cc = nr + dr0, nc + dc0
            set_cell(rr, cc, 14)            # new block cells become 14

    # Process cells that were 1 or 4 and are adjacent to new block
    for rr in range(64):
        for cc in range(64):
            if frame[rr][cc] in (1, 4) and adjacent_to_new_block(rr, cc):
                set_cell(rr, cc, 14)

    return new_frame

